"); console.log("
Here's a list of files in the bucket:"); console.log(`${contentsList}
`); Sometimes you might want to copy an object from one bucket to another. Use the CopyObject command for that. export const copyFileFromBucket = async ({ destinationBucket }) => { const proceed = await prompter.confirm({ message: "Would you like to copy an object from another bucket?", if (!proceed) { const copy = async () => { const sourceBucket = await prompter.input({ message: "Enter source bucket name:", const sourceKey = await prompter.input({ message: "Enter source key:", const destinationKey = await prompter.input({ message: "Enter destination key:", const command = new CopyObjectCommand({ Bucket: destinationBucket, CopySource: `${sourceBucket}/${sourceKey}`, Key: destinationKey, await s3Client.send(command); await copyFileFromBucket({ destinationBucket }); console.error("Copy error."); console.error(err); const retryAnswer = await prompter.confirm({ message: "Try again?" }); if (retryAnswer) { await copy(); await copy(); There's no SDK method for getting multiple objects from a bucket. Instead, you'll create a list of objects to download and iterate over them. export const downloadFilesFromBucket = async ({ bucketName }) => { const { Contents } = await s3Client.send( new ListObjectsCommand({ Bucket: bucketName }), const path = await prompter.input({ message: "Enter destination path for files:", for (const content of Contents) { const obj = await s3Client.send( new GetObjectCommand({ Bucket: bucketName, Key: content.Key }), writeFileSync( `${path}/${content.Key}`, await obj.Body.transformToByteArray(), console.log("Files downloaded successfully.
