# Uploads a file to an Amazon S3 bucket.
@param bucket [Aws::S3::Bucket] The bucket object representing the upload
@return [Aws::S3::Object] The Amazon S3 object that contains the uploaded
file. def upload_file(bucket) File.open('demo.txt', 'w+') { |f| f.write('This is a demo file.') } s3_object = bucket.object(File.basename('demo.txt')) s3_object.upload_file('demo.txt') puts("Uploaded file demo.txt into bucket #{bucket.name} with key
#{s3_object.key}.")
puts("Couldn't upload file demo.txt to #{bucket.name}.") s3_object

# Downloads an Amazon S3 object to a file.
@param s3_object [Aws::S3::Object] The object to download.
def download_file(s3_object) puts("\nDo you want to download #{s3_object.key} to a local file (y/n)? ") answer = gets.chomp.downcase if answer == 'y' puts('Enter a name for the downloaded file: ') file_name = gets.chomp s3_object.download_file(file_name) puts("Object #{s3_object.key} successfully downloaded to #{file_name}.") puts("Couldn't download #{s3_object.key}.")

# Copies an Amazon S3 object to a subfolder within the same bucket.
@param source_object [Aws::S3::Object] The source object to copy.
@return [Aws::S3::Object, nil] The destination object.
def copy_object(source_object) dest_object = nil puts("\nDo you want to copy #{source_object.key} to a subfolder in your bucket (y/n)? ") answer = gets.chomp.downcase if answer == 'y' dest_object = source_object.bucket.object("demo-folder/
#{source_object.key}")
dest_object.copy_from(source_object) puts("Copied #{source_object.key} to #{dest_object.key}.") puts("Couldn't copy #{source_object.key}.") dest_object

# Deletes the objects in an Amazon S3 bucket and deletes the bucket.
@param bucket [Aws::S3::Bucket] The bucket to empty and delete.
def delete_bucket(bucket) puts("\nDo you want to delete all of the objects as well as the bucket (y/n)? ") answer = gets.chomp.downcase if answer == 'y' bucket.objects.batch_delete! bucket.delete puts("Emptied and deleted bucket #{bucket.name}.\n") puts("Couldn't empty and delete bucket #{bucket.name}.")

# Runs the Amazon S3 getting started scenario.
def run_scenario(scenario) puts('-' * 88) puts('Welcome to the Amazon S3 getting started demo!') puts('-' * 88) bucket = scenario.create_bucket s3_object = scenario.upload_file(bucket) scenario.download_file(s3_object) scenario.copy_object(s3_object) scenario.list_objects(bucket) scenario.delete_bucket(bucket) puts('Thanks for watching!') puts('-' * 88) rescue Aws::Errors::ServiceError puts('Something went wrong with the demo!') run_scenario(ScenarioGettingStarted.new(Aws::S3::Resource.new)) if $PROGRAM_NAME == __FILE__ Code for the binary crate which runs the scenario.
