nt object and sets the /// Amazon Simple Storage Service (Amazon S3) bucket name before /// calling EnableAccelerationAsync. var s3Client = new AmazonS3Client(); const string bucketName = "amzn-s3-demo-bucket"; await EnableAccelerationAsync(s3Client, bucketName); /// This method sets the configuration to enable transfer acceleration /// for the bucket referred to in the bucketName parameter. /// <param name="client">An Amazon S3 client used to enable the /// acceleration on an Amazon S3 bucket.</param> /// <param name="bucketName">The name of the Amazon S3 bucket for which /// method will be enabling acceleration.</param> private static async Task EnableAccelerationAsync(AmazonS3Client client, string bucketName) var putRequest = new PutBucketAccelerateConfigurationRequest AccelerateConfiguration = new AccelerateConfiguration Status = BucketAccelerateStatus.Enabled, await client.PutBucketAccelerateConfigurationAsync(putRequest); var getRequest = new GetBucketAccelerateConfigurationRequest client.GetBucketAccelerateConfigurationAsync(getRequest); Console.WriteLine($"Acceleration state = '{response.Status}' "); Console.WriteLine($"Error occurred. Message:'{ex.Message}' when setting transfer acceleration"); To set the accelerate configuration of a bucket The following put-bucket-accelerate-configuration example enables the accelerate configuration for the specified bucket. aws s3api put-bucket-accelerate-configuration
